det_check_template:
proof fn det_new<'a, I: Iterator>(iter: I, init: Ghost<Option<&'a I>>, r1: VerusForLoopWrapper<'a, I>, r2: VerusForLoopWrapper<'a, I>)
    requires (init@ matches Some(i) ==> iter.initial_value_relation(i)),
    ensures
        ({
            &&& (r1.index == 0)
            &&& (r1.snapshot == iter)
            &&& (r1.init == init)
            &&& (r1.iter == iter)
            &&& (r1.history@ == Seq::<I::Item>::empty())
            &&& (r1.wf())
            &&& (r2.index == 0)
            &&& (r2.snapshot == iter)
            &&& (r2.init == init)
            &&& (r2.iter == iter)
            &&& (r2.history@ == Seq::<I::Item>::empty())
            &&& (r2.wf())
        }) ==> det_new_equal::<I>(r1, r2),
{
    reveal(Rev::remaining);
    reveal(VerusForLoopWrapper::wf_inner);
    reveal(Rev::will_return_none);
{ASSUMES}}

equal_fn_def:
// Generated equal-fn for determinism check.
// Policy: errs_equivalent=True, opaque_ok=False
spec fn det_new_equal<'a, I: Iterator>(r1: VerusForLoopWrapper<'a, I>, r2: VerusForLoopWrapper<'a, I>) -> bool {
    (r1 == r2)
}
